1	/**
2	 * lab.probe-git-range — captures every commit between a codex's
3	 * recorded base SHA and its current head, writes one row per commit
4	 * to `lab-trial-codex-commits`. Big-diff tripwire: any single diff
5	 * over 10MB fails the probe (and thus the trial).
6	 *
7	 * The probe runs in the lab-host process and discovers the trial's
8	 * codex via duck-typing on `context.upstream` — any yield with the
9	 * `{codexName, bareLocalPath, baseSha}` shape (the codex-fixture's
10	 * yield form) is a candidate. A single matching codex is required
11	 * unless an explicit `codexName` given is supplied.
12	 *
13	 * Head SHA resolution: we read the bare repo's `main` ref, since the
14	 * bare is the canonical write target — the test guild seals into the
15	 * bare via the codexes plugin's seal flow. The codex-fixture's yield
16	 * carries `headSha = baseSha` at setup time; that field is not
17	 * updated as the trial progresses, so we re-read from the bare.
18	 *
19	 * GIVENS
20	 * ──────
21	 *   trialId    : string?  — Optional; falls back to `_trial.writId`.
22	 *   codexName  : string?  — Optional explicit codex selector. Required
23	 *                          when more than one codex is present in
24	 *                          upstream.
25	 *
26	 * SUMMARY (yields → archive row)
27	 * ──────────────────────────────
28	 *   {
29	 *     codexName       : string,
30	 *     baseSha         : string,
31	 *     headSha         : string,
32	 *     commitCount     : number,
33	 *     totalDiffBytes  : number,
34	 *     capturedAt      : string,
35	 *   }
36	 *
37	 * EXTRACT
38	 * ───────
39	 *   `<targetDir>/codex-history/`
40	 *     ├── commits-manifest.yaml      // ordered metadata
41	 *     └── NNNN-<sha-12>.patch        // one file per commit
42	 */
43	
44	import { execFile as execFileCb } from 'node:child_process';
45	import { promisify } from 'node:util';
46	import { writeFile, mkdir } from 'node:fs/promises';
47	import path from 'node:path';
48	import { stringify as yamlStringify } from 'yaml';
49	import { guild, generateId } from '@shardworks/nexus-core';
50	import type {
51	  EngineRunContext,
52	  EngineRunResult,
53	} from '@shardworks/fabricator-apparatus';
54	import type {
55	  Book,
56	  ReadOnlyBook,
57	  StacksApi,
58	} from '@shardworks/stacks-apparatus';
59	import type { InjectedTrialContext } from '../engines/phases.ts';
60	import {
61	  LAB_TRIAL_CODEX_COMMITS_BOOK,
62	  PER_DIFF_BYTE_CAP,
63	  type LabTrialCodexCommit,
64	} from '../archive/codex-commits-book.ts';
65	import type {
66	  ProbeEngineDesign,
67	  ProbeExtractArgs,
68	  ProbeExtractResult,
69	} from './types.ts';
70	
71	const execFile = promisify(execFileCb);
72	
73	const DESIGN_ID = 'lab.probe-git-range';
74	const EXTRACT_SUBDIR = 'codex-history';
75	const COMMITS_MANIFEST_FILE = 'commits-manifest.yaml';
