78	
79	interface ResolvedGivens {
80	  trialId: string;
81	  codexName?: string;
82	}
83	
84	function validateGivens(rawGivens: Record<string, unknown>): ResolvedGivens {
85	  let trialId = rawGivens.trialId;
86	  if (trialId === undefined || trialId === null) {
87	    const trial = rawGivens._trial as InjectedTrialContext | undefined;
88	    if (trial && typeof trial.writId === 'string' && trial.writId.length > 0) {
89	      trialId = trial.writId;
90	    }
91	  }
92	  if (typeof trialId !== 'string' || trialId.length === 0) {
93	    throw new Error(
94	      `[${DESIGN_ID}] trialId is required (givens.trialId or framework-injected _trial.writId).`,
95	    );
96	  }
97	
98	  let codexName: string | undefined;
99	  if (rawGivens.codexName !== undefined && rawGivens.codexName !== null) {
100	    if (typeof rawGivens.codexName !== 'string' || rawGivens.codexName.length === 0) {
101	      throw new Error(`[${DESIGN_ID}] givens.codexName must be a non-empty string when provided.`);
102	    }
103	    codexName = rawGivens.codexName;
104	  }
105	
106	  return { trialId, codexName };
107	}
