import json

with open('/workspace/nexus-mk2/experiments/X016-orientation-suppression/artifacts/2026-05-02-strong-prompt-2c-n1/stacks-export/animator-transcripts.json') as f:
    data = json.load(f)

# implement session is index 0
row = data[0]
print(f"session: {row['id']}")

msgs = row['messages']
turn = 0
in_turn = False
first_edit_turn = None
edit_tools = {'Edit', 'Write', 'MultiEdit'}

# List of (turn, tool_name, summary) before first productive edit
events = []

for msg in msgs:
    if msg.get('type') == 'assistant':
        if not in_turn:
            turn += 1
            in_turn = True
        inner = msg.get('message', {})
        content = inner.get('content', [])
        if not isinstance(content, list):
            continue
        for piece in content:
            if not isinstance(piece, dict):
                continue
            if piece.get('type') == 'tool_use':
                name = piece.get('name', '')
                inp = piece.get('input') or {}
                # build a summary
                if name in ('Read',):
                    summary = inp.get('file_path', '?')
                    if 'offset' in inp or 'limit' in inp:
                        summary += f"  [offset={inp.get('offset')}, limit={inp.get('limit')}]"
                elif name == 'Bash':
                    summary = (inp.get('command') or '')[:120]
                elif name == 'Glob':
                    summary = inp.get('pattern', '?') + (f"  in {inp.get('path')}" if inp.get('path') else '')
                elif name == 'Grep':
                    summary = inp.get('pattern', '?') + (f"  in {inp.get('path')}" if inp.get('path') else '')
                elif name == 'LS':
                    summary = inp.get('path', '?')
                elif name in edit_tools:
                    summary = inp.get('file_path', '?')
                elif name == 'TodoWrite':
                    todos = inp.get('todos', [])
                    summary = f"({len(todos)} todos)"
